#include "pytorch_npu_helper.hpp"

at::Tensor conv3d_min_softmax_impl_npu(const at::Tensor& x,
                                       const at::Tensor& weight,
                                       const at::Tensor& bias) {
    // Output shape after conv3d (stride=1, pad=0, dilation=1) and min over depth:
    // y: [N, COut, HOut, WOut], where HOut = HIn - KH + 1, WOut = WIn - KW + 1
    TORCH_CHECK(x.dim() == 5 && weight.dim() == 5, "x and weight must be 5D tensors");
    const int64_t N = x.size(0);
    const int64_t COut = weight.size(0);
    const int64_t HOut = x.size(3) - weight.size(3) + 1;
    const int64_t WOut = x.size(4) - weight.size(4) + 1;
    at::Tensor y = at::empty({N, COut, HOut, WOut}, x.options());

    EXEC_NPU_CMD(aclnnConv3dMinSoftmaxCustom, x, weight, bias, y);
    return y;
